export enum ProcessingStage {
  IDLE = 'IDLE',
  EXTRACTING = 'EXTRACTING',
  CHUNKING = 'CHUNKING',
  CLEANING = 'CLEANING',
  STRUCTURING_MACRO = 'STRUCTURING_MACRO', // Step 1
  STRUCTURING_MICRO = 'STRUCTURING_MICRO', // Step 2
  PATCHING = 'PATCHING', // Step 3
  REPAIRING = 'REPAIRING', // New Repair Stage
  TRANSLATING = 'TRANSLATING', // New Verification Stage
  AUDITING = 'AUDITING', // New Stage
}

export type ModelType = 'FLASH_2_0' | 'FLASH' | 'PRO' | 'FLASH_THINKING' | 'GEMINI_3_THINK';

export type LanguageCode = 'AUTO' | 'VI' | 'EN' | 'PT' | 'ES' | 'FR' | 'DE' | 'IT' | 'NL' | 'RU' | 'ZH' | 'JA' | 'KO' | 'AR' | 'HI';

export interface Chunk {
  id: number;
  fileName: string;
  originalText: string;
  cleanedText: string;     // Result of Step 2
  step1Text: string;       // Result of Step 3 (Macro)
  step2Text: string;       // Result of Step 4 (Micro)
  finalText: string;       // Result of Step 5 (Patch)
  translatedText?: string; // Optional Translation
  status: 'PENDING' | 'PROCESSING' | 'COMPLETED' | 'FAILED' | 'SKIPPED';
}

export interface AppState {
  files: File[];
  mode: 'FAST' | 'DEEP_OCR';
  chunkingMode: 'AUTO' | 'Fixed';
  modelType: ModelType;
  cleaningMode: 'DETERMINISTIC' | 'AI';
  targetChunkSize: number;
  chunks: Chunk[];
  stage: ProcessingStage;
  progress: number;
  error: string | null;
  totalTime: number;
  apiCallCount: number;
  auditReport: string | null;
  showTranslation: boolean;
  includeAnnexes: boolean;
  language: LanguageCode;
  autoRunTarget: 'CLEAN' | 'MACRO' | 'MICRO' | 'FINAL' | null;
}
